namespace CodeXCore.ServiceTree
{
    using System;

    /// <summary>
    /// Options for querying Service Tree data from Kusto.
    /// </summary>
    public sealed class ServiceTreeKustoOptions
    {
        /// <summary>
        /// Gets or sets the Kusto cluster URI.
        /// </summary>
        public string ClusterUri { get; set; } = "https://servicetreepublic.westus.kusto.windows.net/";

        /// <summary>
        /// Gets or sets the Kusto database name.
        /// </summary>
        public string Database { get; set; } = "Shared";

        /// <summary>
        /// Gets or sets the token scope override for Kusto.
        /// </summary>
        public string TokenScope { get; set; } = string.Empty;

        /// <summary>
        /// Gets or sets the max number of ids to query in one batch.
        /// </summary>
        public int MaxBatchSize { get; set; } = 200;

        /// <summary>
        /// Gets or sets the hierarchy snapshot table name for flattened lookups.
        /// </summary>
        public string HierarchyTableName { get; set; } = "DataStudio_ServiceTree_Hierarchy_Snapshot";

        /// <summary>
        /// Builds options from environment variables.
        /// </summary>
        /// <returns>Options resolved from environment variables.</returns>
        public static ServiceTreeKustoOptions FromEnvironment()
        {
            var options = new ServiceTreeKustoOptions();

            string? clusterUri = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_CLUSTER_URI");
            if (!string.IsNullOrWhiteSpace(clusterUri))
            {
                options.ClusterUri = clusterUri.Trim();
            }

            string? database = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_DATABASE");
            if (!string.IsNullOrWhiteSpace(database))
            {
                options.Database = database.Trim();
            }

            string? tokenScope = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_TOKEN_SCOPE");
            if (!string.IsNullOrWhiteSpace(tokenScope))
            {
                options.TokenScope = tokenScope.Trim();
            }

            string? maxBatchSize = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_MAX_BATCH");
            if (!string.IsNullOrWhiteSpace(maxBatchSize) && int.TryParse(maxBatchSize, out var parsed))
            {
                options.MaxBatchSize = parsed;
            }

            string? hierarchyTable = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_HIERARCHY_TABLE");
            if (!string.IsNullOrWhiteSpace(hierarchyTable))
            {
                options.HierarchyTableName = hierarchyTable.Trim();
            }

            return options;
        }
    }
}

