    /// </summary>
    public sealed class CodexSite : OnePortalService
    {
        /// <inheritdoc/>
        public override string Name => "CodexSite";

        /// <inheritdoc/>
        public override void InjectDependencies(IServiceCollection services)
        {
            services.AddHttpClient();
            services.AddSingleton<IEnvironmentSetting, EnvironmentSetting>();
            services.AddSingleton<ISecretStore, GalaxyVaultSecretStore>();
            services.AddSingleton<IMicrosoftGraphApiClient, MicrosoftGraphApiClient>();

            services.AddSingleton<IArmClientWrapper, ArmClientAPIProxyWrapper>();
            services.AddSingleton<IArmRestApiWrapper, ArmRestClientAPIProxyWrapper>();

            services.AddSingleton<DBConnectionProperties>();
            services.AddScoped<IUnitOfCodeX, UnitOfCodeX>();
            services.AddSingleton<IAOAIClient>(sp => new AOAIClient(sp.GetService<ICredentialFactory>().CreateTokenCredential(AADTenant.PME)));
            services.AddSingleton<IOCIRestApiClient>(sp => new OCIRestApiClient(new BasicTokenCredAuthProvider(sp.GetService<ICredentialFactory>().CreateTokenCredential(AADTenant.PME))));
            services.AddSingleton<IPaiApiClient>(sp => new PaiApiClient(
                sp.GetService<System.Net.Http.IHttpClientFactory>(),
                sp.GetService<ICredentialFactory>().CreateTokenCredential(),
                sp.GetService<ILogger<PaiApiClient>>()));
            services.AddSingleton<IEnvironmentProperties, EnvironmentProperties>();
            services.AddSingleton<IPapyrusClient, PapyrusClient>();
            services.AddScoped<EndpointUpdater>();
            services.AddScoped<ISKUService, SKUService>();
            services.AddScoped<MssAndMpcpUpdater>();
            services.AddScoped<ICodeXService, CodeXService>();

            services.AddSingleton<IPerfHubStressTestService, PerfHubStressTestService>();
            services.AddSingleton<AdoCredentialFactory>();
            services.AddSingleton<IGitClient>(sp => new GitClient(new TokenProviderDelegatingHandler(new AzureCredentialTokenProvider(new[] { ISExpAuthToolkit.Constants.AzureADDevOpsScope }, sp.GetService<AdoCredentialFactory>().GetPrimaryAdoCredential()))));

            services.AddSingleton<PapyrusEnvironmentProperties>(sp => EnvUtil.ResolvePapyrusEnvProperties(sp.GetService<IEnvironmentProperties>()));
            services.AddSingleton<IPullRequestClient>(sp =>
            {
                var papyrusEnvProps = sp.GetService<PapyrusEnvironmentProperties>();
                var adoCredFactory = sp.GetService<AdoCredentialFactory>();
                return new PullRequestClient(
                    papyrusEnvProps.AdoOrg,
                    papyrusEnvProps.AdoProject,
                    papyrusEnvProps.AdoRep,
                    adoCredFactory.GetPrimaryAdoCredential(),
                    prApprovalCredential: adoCredFactory.GetSecondaryAdoCredential());
            });
            services.AddSingleton<IPapyrusConfigService, PapyrusConfigService>();

            services.AddSingleton<IKeyVaultCertProvider, KeyVaultCertProvider>();
            services.AddSingleton<IPapyrusWeeklyUtilizationService, PapyrusWeeklyUtilizationMdmService>();
            services.AddSingleton<CodexCore.Services.ICapacityCounterMetricsCounters, CodexImplementation.CapacityCounterMetricsCounters>();
            services.AddSingleton<CodeXCore.UtilizationMetricCollection.Counter.IUtilizationCounterManager, CodeXCore.UtilizationMetricCollection.Counter.CompositeUtilizationCounterManager>();
            services.AddSingleton<IPapyrusConfigChangeValidator, PapyrusConfigChangeValidator>();
            services.AddSingleton(ServiceTreeClientOptions.FromEnvironment());
            services.AddSingleton(ServiceTreeKustoOptions.FromEnvironment());
            services.AddSingleton<IServiceTreeNodeLookup, ServiceTreeKustoClient>();
            services.AddSingleton<IServiceTreeParentResolver, ServiceTreeParentResolver>();
            services.AddSingleton<IAppIdToProductResolver, AppIdToProductResolver>();

            var isTestMode = !string.IsNullOrEmpty(Environment.GetEnvironmentVariable("IS_TEST"));
            if (isTestMode)
            {
                services.AddSingleton<IRolePermissionService, CodeXCore.Mocks.MockRolePermissionService>();
            }
            else
            {
                services.AddSingleton<IRolePermissionService, RolePermissionService>();
            }

            // TODO , use reflection to do this and move it to shared lib
            // https://msasg.visualstudio.com/Bing_and_IPG/_backlogs/backlog/IndexServe%20Experimental%20Team/Stories?showParents=false&workitem=8214553
            services.AddGeneratedLoggingTypes();

            services.AddMdmLogging(options =>
            {
                options.AddCounterRule(
                    "Microsoft.Falcon.CodexSite",
                    "BingIndexServeGalaxy",
                    "CodexCapacity");
            });

            services.AddParallaxType<IServiceConfig>(Path.Combine("Config", "Config.ini"));
        }
    }
}

