namespace CodeXCore.ServiceTree
{
    using System;

    /// <summary>
    /// Options for Service Tree client configuration.
    /// </summary>
    public sealed class ServiceTreeClientOptions
    {
        private const string DefaultEndpoint = "https://servicetree.msftcloudes.com/api";
        private const string DefaultManagedIdentityClientId = "c49a32cb-df08-439a-be5a-56e2b0fe5afe";

        /// <summary>
        /// Gets or sets the Service Tree API endpoint.
        /// </summary>
        public string Endpoint { get; set; } = DefaultEndpoint;

        /// <summary>
        /// Gets or sets the managed identity client ID used for DefaultAzureCredential.
        /// </summary>
        public string ManagedIdentityClientId { get; set; } = DefaultManagedIdentityClientId;

        /// <summary>
        /// Builds options from environment variables.
        /// </summary>
        /// <returns>Options resolved from environment variables.</returns>
        public static ServiceTreeClientOptions FromEnvironment()
        {
            var options = new ServiceTreeClientOptions();

            string? endpoint = Environment.GetEnvironmentVariable("SERVICETREE_ENDPOINT");
            if (!string.IsNullOrWhiteSpace(endpoint))
            {
                options.Endpoint = endpoint.Trim();
            }

            string? clientId = Environment.GetEnvironmentVariable("SERVICETREE_AAD_CLIENT_ID");
            if (!string.IsNullOrWhiteSpace(clientId))
            {
                options.ManagedIdentityClientId = clientId.Trim();
            }

            return options;
        }
    }
}

