        private TokenCredential? ResolveTokenCredential(
            ICredentialFactory? credentialFactory,
            ServiceTreeClientOptions options)
        {
            // When ICredentialFactory is available AND auth mode is DefaultAzureCredential,
            // use the factory for cross-tenant support (PME MSI ŌåÆ MSFT tenant token).
            if (credentialFactory != null
                && options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
            {
                try
                {
                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
                    this.logger.LogInformation(
                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
                        cred.GetType().Name);
                    return cred;
                }
                catch (Exception ex)
                {
                    this.logger.LogError(
                        ex,
                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
                    throw;
                }
            }

            return this.CreateTokenCredential(options);
        }

        private TokenCredential? CreateTokenCredential(ServiceTreeClientOptions options)
        {
            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.DefaultAzureCredential)
            {
                return new DefaultAzureCredential(new DefaultAzureCredentialOptions
                {
                    ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.AadClientId) ? null : options.AadClientId,
                });
            }

            if (options.AuthenticationMode == ServiceTreeAuthenticationMode.Aad)
            {
                if (!string.IsNullOrWhiteSpace(options.AadClientSecret)
                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
                    && !string.IsNullOrWhiteSpace(options.AadClientId))
                {
                    return new ClientSecretCredential(options.AadTenantId, options.AadClientId, options.AadClientSecret);
                }

                if (!string.IsNullOrWhiteSpace(options.AadClientCertificateBase64)
                    && !string.IsNullOrWhiteSpace(options.AadTenantId)
                    && !string.IsNullOrWhiteSpace(options.AadClientId))
                {
#pragma warning disable CA2000 // Certificate lifetime is tied to the credential.
                    var cert = this.TryLoadAadCertificate(options);
#pragma warning restore CA2000
                    if (cert == null)
                    {
                        return null;
                    }

                    return new ClientCertificateCredential(
                        options.AadTenantId,
                        options.AadClientId,
                        cert,
                        new ClientCertificateCredentialOptions { SendCertificateChain = true });
                }

                if (!string.IsNullOrWhiteSpace(options.AadClientId))
                {
                    return new ManagedIdentityCredential(options.AadClientId);
                }

                return new ManagedIdentityCredential();
            }

            return null;
        }

        private string NormalizeIdentifier(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return value;
            }

            var trimmed = value.Trim();
            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
                ? trimmed
                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
        }

