 98ŌåÆ            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
 99ŌåÆ            if (!this.isConfigured)
100ŌåÆ            {
101ŌåÆ                return results;
102ŌåÆ            }
103ŌåÆ
104ŌåÆ            var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
105ŌåÆ                .Where(id => !string.IsNullOrWhiteSpace(id))
106ŌåÆ                .Select(id => id.Trim())
107ŌåÆ                .Distinct(StringComparer.OrdinalIgnoreCase)
108ŌåÆ                .ToList();
109ŌåÆ
110ŌåÆ            if (uniqueIds.Count == 0)
111ŌåÆ            {
112ŌåÆ                return results;
113ŌåÆ            }
114ŌåÆ
115ŌåÆ            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
116ŌåÆ            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
117ŌåÆ            var tasks = batches.Select(async batch =>
118ŌåÆ            {
119ŌåÆ                await semaphore.WaitAsync(cancellationToken);
120ŌåÆ                try
121ŌåÆ                {
122ŌåÆ                    var batchResults = await this.QueryHierarchyBatchAsync(batch, cancellationToken);
123ŌåÆ                    foreach (var pair in batchResults)
124ŌåÆ                    {
125ŌåÆ                        results[pair.Key] = pair.Value;
126ŌåÆ                    }
127ŌåÆ                }
128ŌåÆ                catch (OperationCanceledException)
129ŌåÆ                {
130ŌåÆ                    throw;
131ŌåÆ                }
132ŌåÆ                catch (Exception ex)
133ŌåÆ                {
134ŌåÆ                    this.logger.LogWarning(
135ŌåÆ                        ex,
136ŌåÆ                        "ServiceTreeKustoClient: Batch of {BatchCount} IDs failed; continuing with remaining batches.",
137ŌåÆ                        batch.Count);
138ŌåÆ                }
139ŌåÆ                finally
140ŌåÆ                {
141ŌåÆ                    semaphore.Release();
142ŌåÆ                }
143ŌåÆ            }).ToList();
144ŌåÆ
145ŌåÆ            await Task.WhenAll(tasks);
146ŌåÆ            return results;
147ŌåÆ        }
