154ŌåÆ        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
155ŌåÆ            IReadOnlyList<string> batch,
156ŌåÆ            CancellationToken cancellationToken)
157ŌåÆ        {
158ŌåÆ            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
159ŌåÆ            if (batch.Count == 0)
160ŌåÆ            {
161ŌåÆ                return results;
162ŌåÆ            }
163ŌåÆ
164ŌåÆ            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
165ŌåÆ            // cross-key results by whichever hierarchy column matched each row.
166ŌåÆ            var batchSet = new HashSet<string>(
167ŌåÆ                batch.Select(id => id.ToLowerInvariant()),
168ŌåÆ                StringComparer.OrdinalIgnoreCase);
169ŌåÆ
170ŌåÆ            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
171ŌåÆ            var builder = new StringBuilder();
172ŌåÆ            builder.AppendLine("let ids = datatable(TargetId:string)[");
173ŌåÆ            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
174ŌåÆ            builder.AppendLine("];");
175ŌåÆ            builder.AppendLine($"{hierarchyTable}");
176ŌåÆ            builder.AppendLine("| where tolower(ServiceId) in (ids)");
177ŌåÆ            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
178ŌåÆ            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
179ŌåÆ            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
180ŌåÆ            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
181ŌåÆ            builder.AppendLine("| project");
182ŌåÆ            builder.AppendLine("    Id = tostring(ServiceId),");
183ŌåÆ            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
184ŌåÆ            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
185ŌåÆ            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
186ŌåÆ            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
187ŌåÆ            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
188ŌåÆ            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
189ŌåÆ            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
190ŌåÆ            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
191ŌåÆ            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
192ŌåÆ            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
193ŌåÆ            var query = builder.ToString();
194ŌåÆ
195ŌåÆ            var requestProperties = new ClientRequestProperties();
196ŌåÆ            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
197ŌåÆ
198ŌåÆ            try
199ŌåÆ            {
200ŌåÆ                this.logger.LogInformation(
201ŌåÆ                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
202ŌåÆ                    batch.Count,
203ŌåÆ                    this.kustoOptions.ClusterUri,
204ŌåÆ                    this.kustoOptions.Database,
205ŌåÆ                    this.kustoOptions.HierarchyTableName);
206ŌåÆ
207ŌåÆ                using var provider = this.CreateQueryProvider();
208ŌåÆ                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
209ŌåÆ
210ŌåÆ                do
211ŌåÆ                {
212ŌåÆ                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
213ŌåÆ                    if (idOrdinal < 0)
214ŌåÆ                    {
215ŌåÆ                        continue;
216ŌåÆ                    }
217ŌåÆ
218ŌåÆ                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
219ŌåÆ                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
220ŌåÆ                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
221ŌåÆ                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
222ŌåÆ                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
223ŌåÆ                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
224ŌåÆ                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
225ŌåÆ                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
226ŌåÆ                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
227ŌåÆ
228ŌåÆ                    while (reader.Read())
229ŌåÆ                    {
230ŌåÆ                        var id = this.ReadString(reader, idOrdinal);
231ŌåÆ                        if (string.IsNullOrWhiteSpace(id))
232ŌåÆ                        {
233ŌåÆ                            continue;
234ŌåÆ                        }
235ŌåÆ
236ŌåÆ                        var node = new ServiceTreeNode
237ŌåÆ                        {
238ŌåÆ                            Id = id,
239ŌåÆ                            Name = this.ReadString(reader, nameOrdinal),
240ŌåÆ                            Level = this.ReadString(reader, levelOrdinal),
241ŌåÆ                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
242ŌåÆ                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
243ŌåÆ                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
244ŌåÆ                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
245ŌåÆ                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
246ŌåÆ                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
247ŌåÆ                        };
248ŌåÆ
249ŌåÆ                        // Always key by the native ServiceId for backward compatibility.
250ŌåÆ                        results[id] = node;
251ŌåÆ
252ŌåÆ                        // Also key by any hierarchy ancestor ID that the caller asked for.
253ŌåÆ                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
254ŌåÆ                        // find the result via hierarchyResults.TryGetValue(inputId).
255ŌåÆ                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
256ŌåÆ                        foreach (var hierarchyId in new[]
257ŌåÆ                        {
258ŌåÆ                            teamGroupId,
259ŌåÆ                            node.ServiceGroupId,
260ŌåÆ                            node.OrganizationId,
261ŌåÆ                            node.DivisionId,
262ŌåÆ                        })
263ŌåÆ                        {
264ŌåÆ                            if (!string.IsNullOrWhiteSpace(hierarchyId)
265ŌåÆ                                && batchSet.Contains(hierarchyId.ToLowerInvariant()))
266ŌåÆ                            {
267ŌåÆ                                results[hierarchyId] = node;
268ŌåÆ                            }
269ŌåÆ                        }
270ŌåÆ                    }
271ŌåÆ                }
272ŌåÆ                while (results.Count == 0 && reader.NextResult());
273ŌåÆ
274ŌåÆ                this.logger.LogInformation(
275ŌåÆ                    "ServiceTreeKustoClient: Hierarchy query completed. Returned {ResultCount} results for {BatchCount} input IDs.",
276ŌåÆ                    results.Count,
277ŌåÆ                    batch.Count);
278ŌåÆ            }
279ŌåÆ            catch (OperationCanceledException)
280ŌåÆ            {
281ŌåÆ                throw;
282ŌåÆ            }
283ŌåÆ            catch (Exception ex)
284ŌåÆ            {
285ŌåÆ                this.logger.LogError(
286ŌåÆ                    ex,
287ŌåÆ                    "ServiceTreeKustoClient: hierarchy query failed. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, BatchCount={BatchCount}.",
288ŌåÆ                    this.kustoOptions.ClusterUri,
289ŌåÆ                    this.kustoOptions.Database,
290ŌåÆ                    this.kustoOptions.HierarchyTableName,
291ŌåÆ                    this.tokenCredential?.GetType().Name ?? "null",
292ŌåÆ                    batch.Count);
293ŌåÆ                throw;
294ŌåÆ            }
295ŌåÆ
296ŌåÆ            return results;
297ŌåÆ        }
