306ŌåÆ        private IEnumerable<IReadOnlyList<string>> SplitStringBatches(IReadOnlyList<string> ids, int batchSize)
307ŌåÆ        {
308ŌåÆ            for (int i = 0; i < ids.Count; i += batchSize)
309ŌåÆ            {
310ŌåÆ                var count = Math.Min(batchSize, ids.Count - i);
311ŌåÆ                var batch = new List<string>(count);
312ŌåÆ                for (int j = 0; j < count; j++)
313ŌåÆ                {
314ŌåÆ                    batch.Add(ids[i + j]);
315ŌåÆ                }
316ŌåÆ
317ŌåÆ                yield return batch;
318ŌåÆ            }
319ŌåÆ        }
