19ŌåÆ    /// by fetching service auth quotas and resolving their Service Tree parents.
20ŌåÆ    /// </summary>
21ŌåÆ    public sealed class AppIdToProductResolver : IAppIdToProductResolver
22ŌåÆ    {
23ŌåÆ        private readonly IPapyrusConfigService configService;
