27ŌåÆ        /// <summary>
28ŌåÆ        /// Initializes a new instance of the <see cref="AppIdToProductResolver"/> class.
29ŌåÆ        /// </summary>
30ŌåÆ        /// <param name="configService">Papyrus config service for fetching service auth quotas.</param>
31ŌåÆ        /// <param name="parentResolver">Service Tree parent resolver.</param>
32ŌåÆ        /// <param name="logger">Logger.</param>
33ŌåÆ        public AppIdToProductResolver(
34ŌåÆ            IPapyrusConfigService configService,
35ŌåÆ            IServiceTreeParentResolver parentResolver,
36ŌåÆ            ILogger<AppIdToProductResolver> logger)
37ŌåÆ        {
38ŌåÆ            this.configService = configService ?? throw new ArgumentNullException(nameof(configService));
39ŌåÆ            this.parentResolver = parentResolver ?? throw new ArgumentNullException(nameof(parentResolver));
40ŌåÆ            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
41ŌåÆ        }
