43ŌåÆ        /// <inheritdoc/>
44ŌåÆ        public async Task<IReadOnlyDictionary<string, string>> ResolveAsync(CancellationToken cancellationToken)
45ŌåÆ        {
46ŌåÆ            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
47ŌåÆ
48ŌåÆ            try
49ŌåÆ            {
50ŌåÆ                // 1. Fetch all service auth quota entries.
51ŌåÆ                var serviceAuthQuotas = await this.configService
52ŌåÆ                    .GetServiceQuotaAndAuthManagementAsync(string.Empty);
53ŌåÆ
54ŌåÆ                if (serviceAuthQuotas == null || serviceAuthQuotas.Count == 0)
55ŌåÆ                {
56ŌåÆ                    this.logger.LogWarning("AppIdToProductResolver: No service auth quotas found.");
57ŌåÆ                    return result;
58ŌåÆ                }
59ŌåÆ
60ŌåÆ                // 2. Resolve their ServiceTreeIds to parent groups.
61ŌåÆ                var serviceTreeIds = serviceAuthQuotas
62ŌåÆ                    .Select(q => q.ServiceTreeId ?? string.Empty)
63ŌåÆ                    .Where(id => !string.IsNullOrWhiteSpace(id))
64ŌåÆ                    .Distinct(StringComparer.OrdinalIgnoreCase);
65ŌåÆ
66ŌåÆ                var parentLookup = await this.parentResolver
67ŌåÆ                    .ResolveParentsAsync(serviceTreeIds, cancellationToken);
68ŌåÆ
69ŌåÆ                // 3. Build QuotaAppId ŌåÆ Product mapping.
70ŌåÆ                foreach (var entry in serviceAuthQuotas)
71ŌåÆ                {
72ŌåÆ                    if (string.IsNullOrEmpty(entry.QuotaAppId))
73ŌåÆ                    {
74ŌåÆ                        continue;
75ŌåÆ                    }
76ŌåÆ
77ŌåÆ                    if (parentLookup.TryGetValue(entry.ServiceTreeId ?? string.Empty, out var parent)
78ŌåÆ                        && !string.IsNullOrEmpty(parent.Product))
79ŌåÆ                    {
80ŌåÆ                        result.TryAdd(entry.QuotaAppId, parent.Product);
81ŌåÆ                    }
82ŌåÆ                }
83ŌåÆ
84ŌåÆ                this.logger.LogInformation(
85ŌåÆ                    "AppIdToProductResolver resolved {Count} AppIdŌåÆProduct mappings from {TotalCount} service auth quotas.",
86ŌåÆ                    result.Count,
87ŌåÆ                    serviceAuthQuotas.Count);
88ŌåÆ            }
89ŌåÆ            catch (Exception ex)
90ŌåÆ            {
91ŌåÆ                this.logger.LogError(ex, "AppIdToProductResolver failed to resolve AppIdŌåÆProduct mappings.");
92ŌåÆ            }
93ŌåÆ
