// </copyright>

namespace CodeXCore.ServiceTree
{
    using System;
    using System.Collections.Concurrent;
    using System.Collections.Generic;
    using System.Linq;
    using System.Text;
    using System.Threading;
    using System.Threading.Tasks;
    using Microsoft.Extensions.Logging;

    /// <summary>
    /// Resolves Service Tree node parent group info using the flattened hierarchy table and a hardcoded catalog.
    /// </summary>
    public sealed class ServiceTreeParentResolver : IServiceTreeParentResolver
    {
        private static readonly ParentServiceGroupInfo UnknownParent = new ParentServiceGroupInfo(string.Empty, string.Empty, string.Empty);

        private readonly IServiceTreeNodeLookup nodeLookup;
        private readonly ILogger<ServiceTreeParentResolver> logger;
        private readonly ConcurrentDictionary<string, ParentServiceGroupInfo> cache =
            new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);

        /// <summary>
        /// Initializes a new instance of the <see cref="ServiceTreeParentResolver"/> class.
        /// </summary>
        /// <param name="nodeLookup">Service Tree node lookup.</param>
        /// <param name="logger">Logger instance.</param>
        public ServiceTreeParentResolver(IServiceTreeNodeLookup nodeLookup, ILogger<ServiceTreeParentResolver> logger)
        {
            this.nodeLookup = nodeLookup ?? throw new ArgumentNullException(nameof(nodeLookup));
            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
        }

        /// <inheritdoc/>
        public async Task<IReadOnlyDictionary<string, ParentServiceGroupInfo>> ResolveParentsAsync(
            IEnumerable<string> serviceTreeIds,
            CancellationToken cancellationToken)
        {
            var results = new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
            var uniqueIds = (serviceTreeIds ?? Enumerable.Empty<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (uniqueIds.Count == 0)
            {
                return results;
            }

            var idsToQuery = new List<string>();

            foreach (var id in uniqueIds)
            {
                if (this.cache.TryGetValue(id, out var cached))
                {
                    results[id] = cached;
                    continue;
                }

                if (ServiceTreeParentGroupCatalog.ParentsById.TryGetValue(id, out var directMatch))
                {
                    this.cache[id] = directMatch;
                    results[id] = directMatch;
                    continue;
                }

                idsToQuery.Add(id);
            }

            if (idsToQuery.Count > 0)
            {
                // Use the flattened hierarchy table ŌĆö one query, no traversal needed.
                var hierarchyResults = await this.nodeLookup
                    .GetHierarchyNodesByServiceIdsAsync(idsToQuery, cancellationToken)
                    .ConfigureAwait(false);

                this.logger.LogInformation(
                    "ServiceTreeParentResolver: Queried {QueryCount} IDs, got {ResultCount} hierarchy results.",
                    idsToQuery.Count,
                    hierarchyResults.Count);

                foreach (var id in idsToQuery)
                {
                    if (hierarchyResults.TryGetValue(id, out var hierarchyNode))
                    {
                        var parent = this.MatchFromHierarchyNode(hierarchyNode);
                        if (parent != null)
                        {
                            this.logger.LogInformation(
                                "ServiceTreeParentResolver: Resolved {Id} ŌåÆ ServiceGroupId={ServiceGroupId}, ServiceGroupName={ServiceGroupName}, Product={Product}.",
                                id,
                                parent.ServiceGroupId,
                                parent.ServiceGroupName,
                                parent.Product);
                            this.cache[id] = parent;
                            results[id] = parent;
                            continue;
                        }

                        this.logger.LogWarning(
                            "ServiceTreeParentResolver: Hierarchy returned node for {Id} but no ServiceGroupId found.",
                            id);
                    }
                    else
                    {
                        this.logger.LogWarning(
                            "ServiceTreeParentResolver: No hierarchy result for {Id}.",
                            id);
                    }

                    // Not found in hierarchy or no ServiceGroupId ŌĆö mark as unknown.
                    this.cache[id] = UnknownParent;
                    results[id] = UnknownParent;
                }
            }

            return results;
        }

        private ParentServiceGroupInfo? MatchFromHierarchyNode(ServiceTreeNode node)
        {
            // Check each ancestor level by ID first, then by name.
            // Order: ServiceGroup ŌåÆ Organization ŌåÆ Division (most specific to least).
            string[] ancestorIds = new[]
            {
                node.ServiceGroupId,
                node.OrganizationId,
                node.DivisionId,
            };

            foreach (var ancestorId in ancestorIds)
            {
                if (!string.IsNullOrWhiteSpace(ancestorId)
                    && ServiceTreeParentGroupCatalog.ParentsById.TryGetValue(ancestorId, out var match))
                {
                    return match;
                }
            }

            string[] ancestorNames = new[]
            {
                node.ServiceGroupName,
                node.OrganizationName,
                node.DivisionName,
            };

            foreach (var name in ancestorNames)
            {
                var nameMatch = this.MatchParentByName(name);
                if (nameMatch != null)
                {
                    return nameMatch;
                }
            }

            // No catalog match ŌĆö but if the hierarchy provides a ServiceGroupId,
            // return it directly with empty Product.
            if (!string.IsNullOrWhiteSpace(node.ServiceGroupId))
            {
                return new ParentServiceGroupInfo(
                    node.ServiceGroupId,
                    node.ServiceGroupName ?? string.Empty,
                    string.Empty);
            }

            return null;
        }

        private ParentServiceGroupInfo? MatchParentByName(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
            {
                return null;
            }

            var normalizedName = this.NormalizeName(name);
            foreach (var parent in ServiceTreeParentGroupCatalog.ParentsByNameDescending)
            {
                if (this.NormalizeName(parent.ServiceGroupName) == normalizedName)
                {
                    return parent;
                }
            }

            return null;
        }

        private string NormalizeName(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            var normalized = input.Replace("&", "and", StringComparison.OrdinalIgnoreCase);
            var builder = new StringBuilder(normalized.Length);
            foreach (var ch in normalized)
            {
                if (char.IsLetterOrDigit(ch))
                {
                    builder.Append(char.ToLowerInvariant(ch));
                }
                else if (char.IsWhiteSpace(ch))
                {
                    builder.Append(' ');
                }
            }

            return string.Join(' ', builder.ToString().Split(' ', StringSplitOptions.RemoveEmptyEntries));
        }
    }
}

