210ŌåÆ                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
211ŌåÆ                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
212ŌåÆ                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
213ŌåÆ                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
214ŌåÆ                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
