265ŌåÆ                    results.Count,
266ŌåÆ                    batch.Count);
267ŌåÆ            }
268ŌåÆ            catch (OperationCanceledException)
269ŌåÆ            {
270ŌåÆ                throw;
271ŌåÆ            }
272ŌåÆ            catch (Exception ex)
273ŌåÆ            {
274ŌåÆ                this.logger.LogError(
275ŌåÆ                    ex,
276ŌåÆ                    "ServiceTreeKustoClient: hierarchy query failed. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, BatchCount={BatchCount}.",
277ŌåÆ                    this.kustoOptions.ClusterUri,
278ŌåÆ                    this.kustoOptions.Database,
279ŌåÆ                    this.kustoOptions.HierarchyTableName,
280ŌåÆ                    this.tokenCredential.GetType().Name,
