    /// <param name="kustoOptions">Kusto options.</param>
    /// <param name="logger">Logger instance.</param>
    /// <param name="credentialFactory">Credential factory for cross-tenant support.</param>
    public ServiceTreeKustoClient(
        ServiceTreeKustoOptions kustoOptions,
        ILogger<ServiceTreeKustoClient> logger,
        ICredentialFactory credentialFactory)
    {
        this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
        this.logger = logger ?? throw new ArgumentNullException(nameof(logger));

        if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
            || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
        {
            this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
            this.isConfigured = false;
            return;
        }

        this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
        if (string.IsNullOrWhiteSpace(this.tokenScope))
        {
            this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
            this.isConfigured = false;
            return;
        }

        this.tokenCredential = this.ResolveTokenCredential(credentialFactory);

        this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
        this.isConfigured = true;

        this.logger.LogInformation(
            "ServiceTreeKustoClient: Configured. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, TokenScope={TokenScope}.",
            this.kustoOptions.ClusterUri,
            this.kustoOptions.Database,
            this.kustoOptions.HierarchyTableName,
            this.tokenCredential.GetType().Name,
            this.tokenScope);
    }

    /// <inheritdoc/>
    public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetHierarchyNodesByServiceIdsAsync(
        IEnumerable<string> serviceIds,
        CancellationToken cancellationToken)
    {
        var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
        if (!this.isConfigured)
        {
            return results;
        }

        var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
            .Where(id => !string.IsNullOrWhiteSpace(id))
            .Select(id => id.Trim())
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .ToList();

        if (uniqueIds.Count == 0)
        {
            return results;
        }

        var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
